BEGIN
  FOR profile_record IN SELECT id FROM public.profiles LOOP
    INSERT INTO public.notes (user_id, title, content, is_pinned)
    VALUES (profile_record.id, 'Introduction', intro_json, true)
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;
